const WEBHOOKS = [
  'https://crm.ftel.kz/rest/8577/z87m4ks3hqoid0kq',
  'https://crm.ftel.kz/rest/8577/6rrjcp2g8llhgnj8'
];
const DEPT_NAME = 'Департамент по корпоративным продажам';

let webhookIdx = 0;
function getWebhook() {
  return WEBHOOKS[webhookIdx++ % WEBHOOKS.length];
}

async function callBitrix(method, params = {}, retries = 3) {
  const wh = getWebhook();
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `${wh}/${method}`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params)
    });
    const data = typeof response === 'string' ? JSON.parse(response) : response;
    if (data.error === 'QUERY_LIMIT_EXCEEDED' && retries > 0) {
      await new Promise(r => setTimeout(r, 600));
      return callBitrix.call(this, method, params, retries - 1);
    }
    return data;
  } catch (e) {
    if (retries > 0) {
      await new Promise(r => setTimeout(r, 1000));
      return callBitrix.call(this, method, params, retries - 1);
    }
    return { result: [], error: e.message };
  }
}

async function callBitrixAll(method, params = {}) {
  let all = [], start = 0;
  while (true) {
    const data = await callBitrix.call(this, method, { ...params, start });
    const result = data.result || [];
    all.push(...result);
    if (!data.total || all.length >= data.total) break;
    start += 50;
  }
  return all;
}

async function getAllSubDeptIds(parentId) {
  const ids = [parentId];
  const children = await callBitrixAll.call(this, 'department.get', { PARENT: parentId });
  for (const dept of children) {
    const childIds = await getAllSubDeptIds.call(this, Number(dept.ID));
    ids.push(...childIds);
  }
  return ids;
}

async function parallelBatch(items, fn, concurrency = 6) {
  const results = [];
  for (let i = 0; i < items.length; i += concurrency) {
    const batch = items.slice(i, i + concurrency);
    const batchResults = await Promise.all(batch.map(fn));
    results.push(...batchResults);
  }
  return results;
}

const ctx = this;

const spData = await callBitrix.call(ctx, 'crm.type.list');
const smartProcessMap = {};
for (const t of (spData.result?.types || [])) {
  smartProcessMap[`DYNAMIC_${t.entityTypeId}`] = t.title;
}

const deptData = await callBitrix.call(ctx, 'department.get', { NAME: DEPT_NAME });
if (!deptData.result || deptData.result.length === 0) {
  return [{ json: { error: 'Department not found', debug: deptData } }];
}
const rootDeptId = Number(deptData.result[0].ID);

const allDeptIds = await getAllSubDeptIds.call(ctx, rootDeptId);

const allDepts = await callBitrixAll.call(ctx, 'department.get', {});
const deptMap = {};
for (const d of allDepts) deptMap[d.ID] = d.NAME;

const rawUsers = await callBitrixAll.call(ctx, 'user.get', {
  filter: { UF_DEPARTMENT: allDeptIds, ACTIVE: true }
});
const usersMap = new Map();
for (const u of rawUsers) usersMap.set(u.ID, u);
const users = [...usersMap.values()];

const dashboard = await parallelBatch(users, async (user) => {
  const tasks = await callBitrixAll.call(ctx, 'bizproc.task.list', {
    select: ['ID','NAME','DESCRIPTION','PARAMETERS','USER_ID','WORKFLOW_TEMPLATE_NAME','WORKFLOW_STATE','DOCUMENT_NAME','DOCUMENT_URL','MODIFIED','ACTIVITY','WORKFLOW_STARTED','OVERDUE_DATE'],
    filter: { USER_ID: Number(user.ID), STATUS: 0 },
    order: { ID: 'DESC' }
  });
  const userDepts = (user.UF_DEPARTMENT || [])
    .filter(id => allDeptIds.includes(Number(id)))
    .map(id => deptMap[id] || `Отдел #${id}`);
  return {
    user: {
      id: user.ID,
      name: `${user.LAST_NAME || ''} ${user.NAME || ''}`.trim(),
      position: user.WORK_POSITION || '',
      departments: userDepts
    },
    tasksCount: tasks.length,
    tasks: tasks.map(t => {
      const params = t.PARAMETERS || {};
      const buttons = [];
      for (const [k, v] of Object.entries(params)) {
        if (k.endsWith('Label') && v) buttons.push({ key: k, label: v });
      }
      const fields = (params.Fields || []).map(f => ({
        id: f.Id, name: f.Name, type: f.Type,
        required: f.Required || false, multiple: f.Multiple || false,
        description: f.Description || '', options: f.Options || null
      }));
      return {
        id: t.ID, name: t.NAME, description: t.DESCRIPTION || '',
        templateName: t.WORKFLOW_TEMPLATE_NAME, documentName: t.DOCUMENT_NAME,
        documentUrl: t.DOCUMENT_URL, modified: t.MODIFIED,
        workflowStarted: t.WORKFLOW_STARTED, overdueDate: t.OVERDUE_DATE,
        state: t.WORKFLOW_STATE, activity: t.ACTIVITY, buttons, fields
      };
    })
  };
}, 6);

dashboard.sort((a, b) => b.tasksCount - a.tasksCount);

return [{ json: {
  department: DEPT_NAME,
  bitrixUrl: 'https://crm.ftel.kz',
  smartProcesses: smartProcessMap,
  subDepartments: allDeptIds.map(id => ({ id, name: deptMap[id] || `#${id}` })),
  totalUsers: dashboard.length,
  totalTasks: dashboard.reduce((s, u) => s + u.tasksCount, 0),
  updatedAt: new Date().toISOString(),
  employees: dashboard
} }];
